s=''
for c in ''.join(';'.join(C).split()):
    if c.isalpha():
        s+=c*(I==0)
        I=1
    else:
        s+=c*(c!=' ')
        I=0
x=''
t=''
for c in s+' ':
    if c.isdigit():
        x+=c
    else:
        if x:
            if x[-3:]=='000':
                z=x.rstrip('0')
                x=x[:len(z)]+'e'+str(len(x)-len(z))
            t+=x
            x=''
        t+=c
